const ge={className:"BonesBlock",stage:"vertex",emit(e,i,n,s,t){const c=t.resolve(e,"world",n,s);if(!s.hasSkeleton)return c;s.vertex.helpers.set("nme_skinning","fn nme_skinningMatrix(indices:vec4<f32>,weights:vec4<f32>)->mat4x4<f32>{let i0=u32(indices.x);let i1=u32(indices.y);let i2=u32(indices.z);let i3=u32(indices.w);return nmeBones[i0]*weights.x+nmeBones[i1]*weights.y+nmeBones[i2]*weights.z+nmeBones[i3]*weights.w;}");const r=t.cast(t.resolve(e,"matricesIndices",n,s),"vec4f").expr,m=t.cast(t.resolve(e,"matricesWeights",n,s),"vec4f").expr;return{expr:`(${c.expr}*nme_skinningMatrix(${r},${m}))`,type:"mat4f"};}};export{ge as emitter};